import{_ as s,o as a,c as p,ae as l}from"./chunks/framework.Czhw_PXq.js";const h=JSON.parse('{"title":"01 - 网络基础","description":"","frontmatter":{},"headers":[],"relativePath":"01-ios/08_Network_Deep/01_Network_Basics.md","filePath":"01-ios/08_Network_Deep/01_Network_Basics.md"}'),e={name:"01-ios/08_Network_Deep/01_Network_Basics.md"};function i(c,n,t,o,r,u){return a(),p("div",null,[...n[0]||(n[0]=[l(`<h1 id="_01-网络基础" tabindex="-1">01 - 网络基础 <a class="header-anchor" href="#_01-网络基础" aria-label="Permalink to &quot;01 - 网络基础&quot;">​</a></h1><h2 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to &quot;目录&quot;">​</a></h2><ol><li><a href="#1-httphttps-原理">HTTP/HTTPS 原理</a></li><li><a href="#2-urlsession-全栈">URLSession 全栈</a></li><li><a href="#3-请求与响应处理">请求与响应处理</a></li><li><a href="#4-上传下载与进度">上传下载与进度</a></li><li><a href="#5-认证与安全">认证与安全</a></li><li><a href="#6-超时重试与错误处理">超时重试与错误处理</a></li><li><a href="#7-网络状态监测与缓存">网络状态监测与缓存</a></li><li><a href="#8-ats-与-ssl-pinning">ATS 与 SSL Pinning</a></li><li><a href="#9-面试考点汇总">面试考点汇总</a></li></ol><hr><h2 id="_1-http-https-原理" tabindex="-1">1. HTTP/HTTPS 原理 <a class="header-anchor" href="#_1-http-https-原理" aria-label="Permalink to &quot;1. HTTP/HTTPS 原理&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>HTTP/HTTPS 原理深度分析：</span></span>
<span class="line"><span>┌───────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                                                                    │</span></span>
<span class="line"><span>│  HTTP 协议深度：                                                    │</span></span>
<span class="line"><span>│  ┌────────────────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │  // HTTP 版本对比                                             │</span></span>
<span class="line"><span>│  │  ┌───────────┬───────┬──────────────┬───────┬───────┐      │   │</span></span>
<span class="line"><span>│  │  │ 特性      │ HTTP/1.1│ HTTP/2      │ HTTP/3  │ HTTPS │   │</span></span>
<span class="line"><span>│  │  ├───────────┼──────────┼──────────────┼──────────┼────────┤      │   │</span></span>
<span class="line"><span>│  │  │ 连接      │ TCP 长连接 │ 多路复用     │ QUIC    │ TCP+TLS │   │</span></span>
<span class="line"><span>│  │  │ 头部      │ 明文     │ 头部压缩      │ 头部压缩  │ 加密  │   │</span></span>
<span class="line"><span>│  │  │ 流      │ 串行    │ 多流并行      │ 多流并行  │ 加密  │   │</span></span>
<span class="line"><span>│  │  │ 优先级    │ 无      │ 流优先级      │ 流优先级  │ 加密  │   │</span></span>
<span class="line"><span>│  │  │ 服务器推送  │ 无      │ 支持         │ 支持     │ 加密  │   │</span></span>
<span class="line"><span>│  │  │ 安全性    │ 无      │ 无           │ 无       │ ✅   │   │</span></span>
<span class="line"><span>│  │  │ 延迟      │ 高     │ 中           │ 低       │ 中   │   │</span></span>
<span class="line"><span>│  │  └───────────┴──────────┴──────────────┴──────────┴────────┘      │   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  HTTP 请求结构：                                                │</span></span>
<span class="line"><span>│  │  ┌────────────────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │  │  请求行：METHOD URL HTTP/version                           │</span></span>
<span class="line"><span>│  │  │  请求头：Key: Value                                          │</span></span>
<span class="line"><span>│  │  │  请求体：Body                                               │</span></span>
<span class="line"><span>│  │  │                                                              │</span></span>
<span class="line"><span>│  │  │  常用方法：                                                  │</span></span>
<span class="line"><span>│  │  │  • GET — 获取资源                                            │</span></span>
<span class="line"><span>│  │  │  • POST — 提交资源                                           │</span></span>
<span class="line"><span>│  │  │  • PUT — 更新资源                                            │</span></span>
<span class="line"><span>│  │  │  • DELETE — 删除资源                                          │</span></span>
<span class="line"><span>│  │  │  • PATCH — 部分更新资源                                      │</span></span>
<span class="line"><span>│  │  │  • OPTIONS — 获取 CORS 信息                                │</span></span>
<span class="line"><span>│  │  │  • HEAD — 获取头部信息                                        │</span></span>
<span class="line"><span>│  │  └────────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  HTTP 响应结构：                                                │</span></span>
<span class="line"><span>│  │  ┌────────────────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │  │  状态行：HTTP/version Status-Code Status-Text              │</span></span>
<span class="line"><span>│  │  │  响应头：Key: Value                                          │</span></span>
<span class="line"><span>│  │  │  响应体：Body                                               │</span></span>
<span class="line"><span>│  │  │                                                              │</span></span>
<span class="line"><span>│  │  │  状态码分类：                                              │</span></span>
<span class="line"><span>│  │  │  • 1xx — 信息性                                           │</span></span>
<span class="line"><span>│  │  │  • 2xx — 成功（200 OK, 201 Created, 204 No Content）     │</span></span>
<span class="line"><span>│  │  │  • 3xx — 重定向（301 Moved, 304 Not Modified）            │</span></span>
<span class="line"><span>│  │  │  • 4xx — 客户端错误（400 Bad Request, 401 Unauthorized）  │</span></span>
<span class="line"><span>│  │  │  • 5xx — 服务器错误（500 Internal, 502 Bad Gateway）      │</span></span>
<span class="line"><span>│  │  └────────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  HTTPS 原理：                                                 │</span></span>
<span class="line"><span>│  │  ┌────────────────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │  │  // HTTPS 握手流程（TLS）                                     │</span></span>
<span class="line"><span>│  │  │  1. Client Hello — 客户端发送支持的加密套件                    │</span></span>
<span class="line"><span>│  │  │  2. Server Hello — 服务端选择加密套件                        │</span></span>
<span class="line"><span>│  │  │  3. Certificate — 服务端发送证书                              │</span></span>
<span class="line"><span>│  │  │  4. Certificate Verify — 服务端签名验证                      │</span></span>
<span class="line"><span>│  │  │  5. Client Key Exchange — 客户端生成预主密钥                │</span></span>
<span class="line"><span>│  │  │  6. Finished — 双方确认握手完成                             │</span></span>
<span class="line"><span>│  │  │  7. 数据传输 — 使用对称加密                                  │</span></span>
<span class="line"><span>│  │  │                                                              │</span></span>
<span class="line"><span>│  │  │  核心原理：                                               │</span></span>
<span class="line"><span>│  │  │  • 非对称加密（RSA/ECC）用于握手                            │</span></span>
<span class="line"><span>│  │  │  • 对称加密（AES）用于数据传输                              │</span></span>
<span class="line"><span>│  │  │  • 证书用于身份验证（CA 机构颁发）                        │</span></span>
<span class="line"><span>│  │  │  • 哈希算法用于完整性验证（SHA-256）                      │</span></span>
<span class="line"><span>│  │  │  • 签名防止中间人攻击                                      │</span></span>
<span class="line"><span>│  │  │                                                              │</span></span>
<span class="line"><span>│  │  │  常见攻击方式：                                           │</span></span>
<span class="line"><span>│  │  │  • 中间人攻击（MITM）— SSL Pinning 防御                   │</span></span>
<span class="line"><span>│  │  │  • 重放攻击 — Nonce/时间戳防御                           │</span></span>
<span class="line"><span>│  │  │  • DNS 劫持 — HTTPS + HSTS 防御                         │</span></span>
<span class="line"><span>│  │  │  • 证书伪造 — CA 验证 + 证书锁定                          │</span></span>
<span class="line"><span>│  │  └────────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  HTTP/2 多路复用原理：                                       │</span></span>
<span class="line"><span>│  │  ┌───────────────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │  │  // HTTP/2 帧结构                                           │</span></span>
<span class="line"><span>│  │  │  ┌────────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │  │  │  LENGTH (24 bits)                                  │   │</span></span>
<span class="line"><span>│  │  │  │  TYPE (8 bits) — HEADERS/PAYLOAD/DATA/RST_STREAM  │   │</span></span>
<span class="line"><span>│  │  │  │  RESERVED (1 bit)                                 │   │</span></span>
<span class="line"><span>│  │  │  │  FLAGS (8 bits)                                   │   │</span></span>
<span class="line"><span>│  │  │  │  STREAM ID (31 bits)                              │   │</span></span>
<span class="line"><span>│  │  │  └────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│  │  │                                                              │</span></span>
<span class="line"><span>│  │  │  // 与 HTTP/1.1 对比                                          │</span></span>
<span class="line"><span>│  │  │  • HTTP/1.1：串行请求，队头阻塞                              │</span></span>
<span class="line"><span>│  │  │  • HTTP/2：多路复用，无队头阻塞                              │</span></span>
<span class="line"><span>│  │  │  • HTTP/2：头部压缩（HPACK）                              │</span></span>
<span class="line"><span>│  │  │  • HTTP/2：服务器推送（Server Push）                      │</span></span>
<span class="line"><span>│  │  │  • HTTP/2：流优先级控制                                    │</span></span>
<span class="line"><span>│  │  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  HTTP/3（QUIC）原理：                                        │</span></span>
<span class="line"><span>│  │  ┌───────────────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │  │  • 基于 UDP（而非 TCP）                                   │</span></span>
<span class="line"><span>│  │  │  • 内置 TLS 1.3                                          │</span></span>
<span class="line"><span>│  │  │  • 多路复用（无队头阻塞）                                 │</span></span>
<span class="line"><span>│  │  │  • 连接迁移（IP 变化无缝切换）                           │</span></span>
<span class="line"><span>│  │  │  • 0-RTT 握手（快速连接）                               │</span></span>
<span class="line"><span>│  │  │  • 头部压缩（QPACK）                                   │</span></span>
<span class="line"><span>│  │  │  • iOS 15+ 支持 HTTP/3                                │</span></span>
<span class="line"><span>│  │  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  HTTP 协议总结：                                              │</span></span>
<span class="line"><span>│  │  • HTTP/1.1：基础协议，串行请求                             │</span></span>
<span class="line"><span>│  │  • HTTP/2：多路复用，头部压缩，服务器推送                   │</span></span>
<span class="line"><span>│  │  • HTTP/3：基于 UDP，QUIC 协议，快速连接                   │</span></span>
<span class="line"><span>│  │  • HTTPS：TLS 加密，证书验证，安全传输                      │</span></span>
<span class="line"><span>│  │  • SSL Pinning：防止中间人攻击                              │</span></span>
<span class="line"><span>│  │  • HSTS：强制 HTTPS 连接                                  │</span></span>
<span class="line"><span>│  └────────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│                                                                    │</span></span>
<span class="line"><span>│  HTTP/HTTPS 面试高频题：                                           │</span></span>
<span class="line"><span>│  ┌───────────────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │  • GET vs POST 区别                                         │</span></span>
<span class="line"><span>│  │  • HTTP vs HTTPS 区别                                         │</span></span>
<span class="line"><span>│  │  • HTTP/2 多路复用原理                                       │</span></span>
<span class="line"><span>│  │  • HTTPS 握手流程                                          │</span></span>
<span class="line"><span>│  │  • SSL Pinning 原理                                       │</span></span>
<span class="line"><span>│  │  • HTTP/3 QUIC 协议原理                                    │</span></span>
<span class="line"><span>│  │  • HSTS 原理                                              │</span></span>
<span class="line"><span>│  │  • CORS 跨域问题                                           │</span></span>
<span class="line"><span>│  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│                                                                    │</span></span>
<span class="line"><span>└───────────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>*/</span></span></code></pre></div><hr><h2 id="_2-urlsession-全栈" tabindex="-1">2. URLSession 全栈 <a class="header-anchor" href="#_2-urlsession-全栈" aria-label="Permalink to &quot;2. URLSession 全栈&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>URLSession 全栈深度分析：</span></span>
<span class="line"><span>┌───────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  URLSession 核心：                                                  │</span></span>
<span class="line"><span>│  ┌───────────────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │  // URLSession 类型                                        │</span></span>
<span class="line"><span>│  │  • URLSession.shared — 共享实例                           │</span></span>
<span class="line"><span>│  │  • URLSession(configuration:) — 自定义配置               │</span></span>
<span class="line"><span>│  │  • URLSession(configuration: delegate: delegateQueue:) — 代理模式  │</span></span>
<span class="line"><span>│  │  • URLSession(configuration: delegateQueue: identifier:) — 命名实例  │</span></span>
<span class="line"><span>│  │  • URLSession.background — 后台传输                      │</span></span>
<span class="line"><span>│  │  • URLSession.ephemeral — 临时实例（不缓存）              │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  // URLSession 配置                                             │</span></span>
<span class="line"><span>│  │  let config = URLSessionConfiguration.default              │</span></span>
<span class="line"><span>│  │  config.timeoutIntervalForRequest = 30                      │</span></span>
<span class="line"><span>│  │  config.timeoutIntervalForResource = 60                     │</span></span>
<span class="line"><span>│  │  config.httpAdditionalHeaders = [&quot;Content-Type&quot;: &quot;application/json&quot;]  │</span></span>
<span class="line"><span>│  │  config.urlCache = URLCache(memoryCapacity: 50*1024*1024,   │</span></span>
<span class="line"><span>│  │          diskCapacity: 100*1024*1024, diskPath: nil)        │</span></span>
<span class="line"><span>│  │  config.waitsForConnectivity = true                       │</span></span>
<span class="line"><span>│  │  config.httpMaximumConnectionsPerHost = 6                   │</span></span>
<span class="line"><span>│  │  config.requestCachePolicy = .useProtocolCachePolicy         │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  // URLSession Task 类型                                    │</span></span>
<span class="line"><span>│  │  • dataTask — 数据任务                                    │</span></span>
<span class="line"><span>│  │  • downloadTask — 下载任务                                  │</span></span>
<span class="line"><span>│  │  • uploadTask — 上传任务                                    │</span></span>
<span class="line"><span>│  │  • dataTaskWithRequest — 请求任务                            │</span></span>
<span class="line"><span>│  │  • downloadTaskWithRequest — 请求下载任务                    │</span></span>
<span class="line"><span>│  │  • uploadTaskWithRequest — 请求上传任务                      │</span></span>
<span class="line"><span>│  │  • task(for: UUID) — 根据 UUID 获取任务                    │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  // URLSession Task 方法                                     │</span></span>
<span class="line"><span>│  │  let task = URLSession.shared.dataTask(with: url) {         │</span></span>
<span class="line"><span>│  │      data, response, error in                              │</span></span>
<span class="line"><span>│  │      if let error = error {                                │</span></span>
<span class="line"><span>│  │          print(&quot;Error: \\(error)&quot;)                           │</span></span>
<span class="line"><span>│  │          return                                             │</span></span>
<span class="line"><span>│  │      }                                                       │</span></span>
<span class="line"><span>│  │      if let data = data {                                  │</span></span>
<span class="line"><span>│  │          // 处理数据                                          │</span></span>
<span class="line"><span>│  │      }                                                       │</span></span>
<span class="line"><span>│  │  }                                                          │</span></span>
<span class="line"><span>│  │  task.resume()  // 启动任务                                  │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  // URLSession 代理方法                                     │</span></span>
<span class="line"><span>│  │  func urlSession(_ session: URLSession,                    │</span></span>
<span class="line"><span>│  │      dataTask: URLSessionDataTask,                        │</span></span>
<span class="line"><span>│  │      didReceive response: URLResponse,                     │</span></span>
<span class="line"><span>│  │      completionHandler: @escaping (URLSession.)            │</span></span>
<span class="line"><span>│  │      -&gt; Void) {                                             │</span></span>
<span class="line"><span>│  │      completionHandler(.allow)                              │</span></span>
<span class="line"><span>│  │  }                                                         │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  // URLSession 错误处理                                       │</span></span>
<span class="line"><span>│  │  if let error = error as? URLError {                        │</span></span>
<span class="line"><span>│  │      switch error.code {                                   │</span></span>
<span class="line"><span>│  │      case .notConnectedToInternet:                          │</span></span>
<span class="line"><span>│  │          print(&quot;无网络连接&quot;)                                 │</span></span>
<span class="line"><span>│  │      case .networkConnectionLost:                           │</span></span>
<span class="line"><span>│  │          print(&quot;网络连接丢失&quot;)                               │</span></span>
<span class="line"><span>│  │      case .timedOut:                                       │</span></span>
<span class="line"><span>│  │          print(&quot;请求超时&quot;)                                   │</span></span>
<span class="line"><span>│  │      case .secureConnectionFailed:                          │</span></span>
<span class="line"><span>│  │          print(&quot;SSL 错误&quot;)                                   │</span></span>
<span class="line"><span>│  │      default:                                               │</span></span>
<span class="line"><span>│  │          print(&quot;其他错误: \\(error)&quot;)                        │</span></span>
<span class="line"><span>│  │      }                                                      │</span></span>
<span class="line"><span>│  │  }                                                         │</span></span>
<span class="line"><span>│  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  URLSession 配置类型对比：                                    │</span></span>
<span class="line"><span>│  │  ┌───────────┬──────────────┬───────────┬──────────────┐   │   │</span></span>
<span class="line"><span>│  │  │ 配置类型   │ 缓存         │ cookie   │ 代理         │   │   │</span></span>
<span class="line"><span>│  │  ├───────────┼──────────────┼───────────┼──────────────┤   │   │</span></span>
<span class="line"><span>│  │  │ .default  │ 持久化        │ 持久化     │ 用户默认     │   │   │</span></span>
<span class="line"><span>│  │  │ .ephemeral│ 无缓存        │ 无 cookie  │ 无代理       │   │   │</span></span>
<span class="line"><span>│  │  │ .background│ 持久化       │ 无 cookie  │ 后台传输     │   │   │</span></span>
<span class="line"><span>│  │  │ .custom   │ 自定义        │ 自定义     │ 自定义       │   │   │</span></span>
<span class="line"><span>│  │  └───────────┴──────────────┴───────────┴──────────────┘   │   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  URLSession 最佳实践：                                       │</span></span>
<span class="line"><span>│  │  • 使用 shared 实例（单例）                                  │</span></span>
<span class="line"><span>│  │  • 自定义配置（timeout、cache、headers）                  │</span></span>
<span class="line"><span>│  │  • 使用代理方法处理响应                                       │</span></span>
<span class="line"><span>│  │  • 使用后台传输（大文件）                                   │</span></span>
<span class="line"><span>│  │  • 使用 ephemeral 实例（不缓存）                           │</span></span>
<span class="line"><span>│  │  • 错误处理（URLError）                                  │</span></span>
<span class="line"><span>│  │  • 超时设置（30s 请求、60s 资源）                         │</span></span>
<span class="line"><span>│  │  • 连接复用（HTTP/2 多路复用）                              │</span></span>
<span class="line"><span>│  │  • 缓存策略（按需缓存）                                  │</span></span>
<span class="line"><span>│  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│                                                                    │</span></span>
<span class="line"><span>└───────────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>*/</span></span></code></pre></div><hr><h2 id="_3-请求与响应处理" tabindex="-1">3. 请求与响应处理 <a class="header-anchor" href="#_3-请求与响应处理" aria-label="Permalink to &quot;3. 请求与响应处理&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请求与响应处理深度分析：</span></span>
<span class="line"><span>┌───────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  请求处理：                                                     │</span></span>
<span class="line"><span>│  ┌───────────────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │  // URLRequest 构建                                         │</span></span>
<span class="line"><span>│  │  var request = URLRequest(url: url)                        │</span></span>
<span class="line"><span>│  │  request.httpMethod = &quot;POST&quot;                               │</span></span>
<span class="line"><span>│  │  request.httpBody = try? JSONEncoder().encode(body)        │</span></span>
<span class="line"><span>│  │  request.setValue(&quot;application/json&quot;, forHTTPHeaderField: &quot;Content-Type&quot;)  │</span></span>
<span class="line"><span>│  │  request.setValue(&quot;Bearer token&quot;, forHTTPHeaderField: &quot;Authorization&quot;)  │</span></span>
<span class="line"><span>│  │  request.setValue(&quot;gzip&quot;, forHTTPHeaderField: &quot;Accept-Encoding&quot;)  │</span></span>
<span class="line"><span>│  │  request.timeoutInterval = 30                              │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  // 响应处理                                                │</span></span>
<span class="line"><span>│  │  if let httpResponse = response as? HTTPURLResponse {      │</span></span>
<span class="line"><span>│  │      print(&quot;Status: \\(httpResponse.statusCode)&quot;)           │</span></span>
<span class="line"><span>│  │      print(&quot;Headers: \\(httpResponse.allHeaderFields)&quot;)     │</span></span>
<span class="line"><span>│  │  }                                                         │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  // JSON 解析                                              │</span></span>
<span class="line"><span>│  │  do {                                                      │</span></span>
<span class="line"><span>│  │      let json = try JSONSerialization.jsonObject(         │</span></span>
<span class="line"><span>│  │          with: data, options: []) as? [String: Any]        │</span></span>
<span class="line"><span>│  │      // 处理 JSON                                           │</span></span>
<span class="line"><span>│  │  } catch {                                                │</span></span>
<span class="line"><span>│  │      print(&quot;JSON 解析错误: \\(error)&quot;)                       │</span></span>
<span class="line"><span>│  │  }                                                         │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  // Codable 解析                                            │</span></span>
<span class="line"><span>│  │  do {                                                      │</span></span>
<span class="line"><span>│  │      let user = try JSONDecoder().decode(User.self, from: data)  │</span></span>
<span class="line"><span>│  │      // 处理 user                                          │</span></span>
<span class="line"><span>│  │  } catch {                                                │</span></span>
<span class="line"><span>│  │      print(&quot;Codable 解析错误: \\(error)&quot;)                    │</span></span>
<span class="line"><span>│  │  }                                                         │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  ⚠️ 编码问题：                                                │</span></span>
<span class="line"><span>│  │  • 响应编码（Content-Encoding）：gzip/deflate/brotli      │</span></span>
<span class="line"><span>│  │  • 响应类型（Content-Type）：application/json             │</span></span>
<span class="line"><span>│  │  • 响应字符集（Content-Charset）：UTF-8/GBK               │</span></span>
<span class="line"><span>│  │  • 响应长度（Content-Length）：传输长度                     │</span></span>
<span class="line"><span>│  │  • 响应缓存（Cache-Control）：no-cache/no-store           │</span></span>
<span class="line"><span>│  │  • 响应权限（Access-Control）：CORS 策略                  │</span></span>
<span class="line"><span>│  │  • 响应安全（Strict-Transport-Security）：HSTS             │</span></span>
<span class="line"><span>│  │  • 响应内容类型（Content-Disposition）：inline/attachment  │</span></span>
<span class="line"><span>│  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  请求处理总结：                                               │</span></span>
<span class="line"><span>│  │  • 构建 URLRequest（method、headers、body）               │</span></span>
<span class="line"><span>│  │  • 设置 timeoutInterval（30s 请求）                        │</span></span>
<span class="line"><span>│  │  • 设置 Authorization 头（Bearer token）                   │</span></span>
<span class="line"><span>│  │  • 设置 Content-Type（application/json）                  │</span></span>
<span class="line"><span>│  │  • 设置 Accept-Encoding（gzip/brotli）                    │</span></span>
<span class="line"><span>│  │  • 处理响应（HTTPURLResponse）                           │</span></span>
<span class="line"><span>│  │  • 解析数据（JSONSerialization / Codable）                 │</span></span>
<span class="line"><span>│  │  • 错误处理（URLError）                                    │</span></span>
<span class="line"><span>│  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│                                                                    │</span></span>
<span class="line"><span>└───────────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>*/</span></span></code></pre></div><hr><h2 id="_4-上传下载与进度" tabindex="-1">4. 上传下载与进度 <a class="header-anchor" href="#_4-上传下载与进度" aria-label="Permalink to &quot;4. 上传下载与进度&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>上传下载与进度深度分析：</span></span>
<span class="line"><span>┌───────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  下载：                                                           │</span></span>
<span class="line"><span>│  ┌───────────────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │  // 数据下载                                                │</span></span>
<span class="line"><span>│  │  URLSession.shared.dataTask(with: url) { data, _, _ in    │</span></span>
<span class="line"><span>│  │      // 处理下载数据                                        │</span></span>
<span class="line"><span>│  │  }.resume()                                                 │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  // 文件下载                                                │</span></span>
<span class="line"><span>│  │  URLSession.shared.downloadTask(with: url) { url, _, _ in │</span></span>
<span class="line"><span>│  │      // 下载完成，保存文件                                    │</span></span>
<span class="line"><span>│  │      try? FileManager.default.moveItem(                    │</span></span>
<span class="line"><span>│  │          at: url!,                                           │</span></span>
<span class="line"><span>│  │          to: documentsURL.appendingPathComponent(&quot;file.txt&quot;))  │</span></span>
<span class="line"><span>│  │  }.resume()                                                 │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  // 后台下载                                                │</span></span>
<span class="line"><span>│  │  let config = URLSessionConfiguration.background(         │</span></span>
<span class="line"><span>│  │      withIdentifier: &quot;com.app.background&quot;)                 │</span></span>
<span class="line"><span>│  │  let session = URLSession(configuration: config)            │</span></span>
<span class="line"><span>│  │  session.downloadTask(with: url).resume()                  │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  // 进度监听                                                │</span></span>
<span class="line"><span>│  │  URLSession.shared.dataTask(with: url) { data, _, _ in    │</span></span>
<span class="line"><span>│  │      // 处理数据                                            │</span></span>
<span class="line"><span>│  │  } progress: { downloaded, total in                         │</span></span>
<span class="line"><span>│  │      let progress = Double(downloaded) / Double(total) * 100  │</span></span>
<span class="line"><span>│  │      print(&quot;下载进度: \\(progress)%&quot;)                       │</span></span>
<span class="line"><span>│  │  }.resume()                                                 │</span></span>
<span class="line"><span>│  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  上传：                                                       │</span></span>
<span class="line"><span>│  │  ┌───────────────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │  │  // 数据上传                                                │</span></span>
<span class="line"><span>│  │  │  let data = &quot;body&quot;.data(using: .utf8)                    │</span></span>
<span class="line"><span>│  │  │  URLSession.shared.uploadTask(with: request) {           │</span></span>
<span class="line"><span>│  │  │      data, response, error in                            │</span></span>
<span class="line"><span>│  │  │      // 处理上传结果                                      │</span></span>
<span class="line"><span>│  │  │  }.resume()                                               │</span></span>
<span class="line"><span>│  │  │                                                             │</span></span>
<span class="line"><span>│  │  │  // 文件上传                                              │</span></span>
<span class="line"><span>│  │  │  let fileURL = documentsURL.appendingPathComponent(&quot;file.jpg&quot;)  │</span></span>
<span class="line"><span>│  │  │  URLSession.shared.uploadTask(with: request,           │</span></span>
<span class="line"><span>│  │  │      fromFile: fileURL) { data, response, error in       │</span></span>
<span class="line"><span>│  │  │      // 处理上传结果                                      │</span></span>
<span class="line"><span>│  │  │  }.resume()                                               │</span></span>
<span class="line"><span>│  │  │                                                             │</span></span>
<span class="line"><span>│  │  │  // 多部分上传                                              │</span></span>
<span class="line"><span>│  │  │  let boundary = UUID().uuidString                        │</span></span>
<span class="line"><span>│  │  │  request.setValue(&quot;multipart/form-data; boundary=\\(boundary)&quot;,  │</span></span>
<span class="line"><span>│  │  │      forHTTPHeaderField: &quot;Content-Type&quot;)                 │</span></span>
<span class="line"><span>│  │  │  let body = NSMutableData()                              │</span></span>
<span class="line"><span>│  │  │  body.append(&quot;--\\(boundary)\\r\\n&quot;.data(using: .utf8)!)    │</span></span>
<span class="line"><span>│  │  │  body.append(&quot;Content-Disposition: form-data; name=\\&quot;file\\&quot;; filename=\\&quot;file.jpg\\&quot;\\r\\n&quot;)  │</span></span>
<span class="line"><span>│  │  │  body.append(&quot;Content-Type: image/jpeg\\r\\n\\r\\n&quot;.data(using: .utf8)!)  │</span></span>
<span class="line"><span>│  │  │  body.append(fileData)                                    │</span></span>
<span class="line"><span>│  │  │  body.append(&quot;\\r\\n--\\(boundary)--\\r\\n&quot;.data(using: .utf8)!)  │</span></span>
<span class="line"><span>│  │  │  URLSession.shared.uploadTask(with: request, from: body) {  │</span></span>
<span class="line"><span>│  │  │      // 处理上传结果                                    │</span></span>
<span class="line"><span>│  │  │  }.resume()                                               │</span></span>
<span class="line"><span>│  │  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  上传下载对比：                                              │</span></span>
<span class="line"><span>│  │  ┌───────┬───────────────┬───────────────┬───────────────┐   │</span></span>
<span class="line"><span>│  │  │ 特性   │ 下载           │ 上传           │ 进度           │   │</span></span>
<span class="line"><span>│  │  ├───────┼───────────────┼───────────────┼───────────────┤   │</span></span>
<span class="line"><span>│  │  │ URL   │ 从服务器获取    │ 发送到服务器    │ 无              │   │</span></span>
<span class="line"><span>│  │  │ 方法   │ GET/POST      │ POST/Multipart │ 无              │   │</span></span>
<span class="line"><span>│  │  │ 代理   │ downloadTask  │ uploadTask     │ dataTask        │   │</span></span>
<span class="line"><span>│  │  │ 进度   │ downloadTask.progress  │ uploadTask.progress  │ 手动计算       │   │</span></span>
<span class="line"><span>│  │  │ 后台  │ backgroundDownload  │ backgroundUpload  │ 无              │   │</span></span>
<span class="line"><span>│  │  └───────┴───────────────┴───────────────┴───────────────┘   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  上传下载总结：                                               │</span></span>
<span class="line"><span>│  │  • 数据下载：dataTask                                         │</span></span>
<span class="line"><span>│  │  • 文件下载：downloadTask                                      │</span></span>
<span class="line"><span>│  │  • 数据上传：uploadTask                                        │</span></span>
<span class="line"><span>│  │  • 文件上传：uploadTask（multipart/form-data）              │</span></span>
<span class="line"><span>│  │  • 后台传输：background session                                │</span></span>
<span class="line"><span>│  │  • 进度监听：downloadTask/ uploadTask.progress              │</span></span>
<span class="line"><span>│  │  • 错误处理：URLError                                        │</span></span>
<span class="line"><span>│  │  • 超时设置：timeoutInterval                                  │</span></span>
<span class="line"><span>│  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│                                                                    │</span></span>
<span class="line"><span>│  上传下载总结：                                                   │</span></span>
<span class="line"><span>│  • 数据下载：dataTask                                              │</span></span>
<span class="line"><span>│  • 文件下载：downloadTask                                          │</span></span>
<span class="line"><span>│  • 数据上传：uploadTask                                             │</span></span>
<span class="line"><span>│  • 文件上传：uploadTask（multipart/form-data）                   │</span></span>
<span class="line"><span>│  • 后台传输：background session                                    │</span></span>
<span class="line"><span>│  • 进度监听：downloadTask/ uploadTask.progress                  │</span></span>
<span class="line"><span>│  • 错误处理：URLError                                            │</span></span>
<span class="line"><span>│  • 超时设置：timeoutInterval                                     │</span></span>
<span class="line"><span>│                                                                    │</span></span>
<span class="line"><span>└───────────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>*/</span></span></code></pre></div><hr><h2 id="_5-认证与安全" tabindex="-1">5. 认证与安全 <a class="header-anchor" href="#_5-认证与安全" aria-label="Permalink to &quot;5. 认证与安全&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>认证与安全深度分析：</span></span>
<span class="line"><span>┌───────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  OAuth2 认证：                                                    │</span></span>
<span class="line"><span>│  ┌───────────────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │  // OAuth2 流程                                           │</span></span>
<span class="line"><span>│  │  1. 客户端请求授权                                          │</span></span>
<span class="line"><span>│  │  2. 用户授权                                               │</span></span>
<span class="line"><span>│  │  3. 客户端获取授权码                                       │</span></span>
<span class="line"><span>│  │  4. 客户端使用授权码换取 Token                               │</span></span>
<span class="line"><span>│  │  5. 客户端使用 Token 访问资源                               │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  // Token 使用                                              │</span></span>
<span class="line"><span>│  │  request.setValue(&quot;Bearer \\(token)&quot;,                       │</span></span>
<span class="line"><span>│  │      forHTTPHeaderField: &quot;Authorization&quot;)                  │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  认证方案对比：                                             │</span></span>
<span class="line"><span>│  │  ┌───────┬───────────────┬───────────────┬───────────────┐   │</span></span>
<span class="line"><span>│  │  │ 方案  │ JWT           │ OAuth2        │ API Key       │   │</span></span>
<span class="line"><span>│  │  ├───────┼───────────────┼───────────────┼───────────────┤   │</span></span>
<span class="line"><span>│  │  │ 类型  │ 无状态 Token  │ 授权码流程     │ 简单密钥       │   │</span></span>
<span class="line"><span>│  │  │ 安全  │ 高            │ 高            │ 低            │   │</span></span>
<span class="line"><span>│  │  │ 适用  │ 分布式系统     │ 第三方授权     │ 内部 API     │   │</span></span>
<span class="line"><span>│  │  │ 过期  │ 可配置         │ 自动刷新      │ 手动          │   │</span></span>
<span class="line"><span>│  │  └───────┴───────────────┴───────────────┴───────────────┘   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  SSL Pinning 原理：                                          │</span></span>
<span class="line"><span>│  │  ┌───────────────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │  │  // SSL Pinning 实现                                          │</span></span>
<span class="line"><span>│  │  │  func urlSession(_ session: URLSession,                   │</span></span>
<span class="line"><span>│  │  │      didReceive challenge: URLAuthenticationChallenge,    │</span></span>
<span class="line"><span>│  │  │      completionHandler: @escaping (URLSession.             │</span></span>
<span class="line"><span>│  │  │      AuthChallengeDisposition, URLCredential?) -&gt; Void) {  │</span></span>
<span class="line"><span>│  │  │      if challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust {  │</span></span>
<span class="line"><span>│  │  │          let serverTrust = challenge.protectionSpace.serverTrust!  │</span></span>
<span class="line"><span>│  │  │          let credential = URLCredential(trust: serverTrust)  │</span></span>
<span class="line"><span>│  │  │          completionHandler(.useCredential, credential)     │</span></span>
<span class="line"><span>│  │  │      } else {                                            │</span></span>
<span class="line"><span>│  │  │          completionHandler(.cancelAuthenticationChallenge, nil)  │</span></span>
<span class="line"><span>│  │  │      }                                                      │</span></span>
<span class="line"><span>│  │  │  }                                                        │</span></span>
<span class="line"><span>│  │  │                                                            │</span></span>
<span class="line"><span>│  │  │  // 证书验证                                             │</span></span>
<span class="line"><span>│  │  │  SecTrustEvaluate(serverTrust, &amp;trustResult)              │</span></span>
<span class="line"><span>│  │  │  SecTrustGetCertificateCount(serverTrust)                 │</span></span>
<span class="line"><span>│  │  │  SecTrustGetCertificateAtIndex(serverTrust, 0)            │</span></span>
<span class="line"><span>│  │  │                                                            │</span></span>
<span class="line"><span>│  │  │  // SSL Pinning 方案                                        │</span></span>
<span class="line"><span>│  │  │  • 公钥锁定（PublicKey Pinning）                          │</span></span>
<span class="line"><span>│  │  │  • 证书锁定（Certificate Pinning）                      │</span></span>
<span class="line"><span>│  │  │  • 指纹锁定（Fingerprint Pinning）                      │</span></span>
<span class="line"><span>│  │  │  • 混合锁定（Hybrid Pinning）                          │</span></span>
<span class="line"><span>│  │  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  认证与安全总结：                                             │</span></span>
<span class="line"><span>│  │  • OAuth2 认证流程（授权码、Token 刷新）                      │</span></span>
<span class="line"><span>│  │  • JWT Token（无状态认证）                                    │</span></span>
<span class="line"><span>│  │  • API Key（简单密钥认证）                                    │</span></span>
<span class="line"><span>│  │  • SSL Pinning（防止中间人攻击）                              │</span></span>
<span class="line"><span>│  │  • 证书验证（SecTrustEvaluate）                              │</span></span>
<span class="line"><span>│  │  • 公钥锁定（PublicKey Pinning）                              │</span></span>
<span class="line"><span>│  │  • 证书锁定（Certificate Pinning）                          │</span></span>
<span class="line"><span>│  │  • 指纹锁定（Fingerprint Pinning）                          │</span></span>
<span class="line"><span>│  │  • 混合锁定（Hybrid Pinning）                               │</span></span>
<span class="line"><span>│  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│                                                                    │</span></span>
<span class="line"><span>│  认证与安全总结：                                                 │</span></span>
<span class="line"><span>│  • OAuth2 认证流程（授权码、Token 刷新）                           │</span></span>
<span class="line"><span>│  • JWT Token（无状态认证）                                        │</span></span>
<span class="line"><span>│  • API Key（简单密钥认证）                                        │</span></span>
<span class="line"><span>│  • SSL Pinning（防止中间人攻击）                                    │</span></span>
<span class="line"><span>│  • 证书验证（SecTrustEvaluate）                                  │</span></span>
<span class="line"><span>│  • 公钥锁定（PublicKey Pinning）                                  │</span></span>
<span class="line"><span>│  • 证书锁定（Certificate Pinning）                              │</span></span>
<span class="line"><span>│  • 指纹锁定（Fingerprint Pinning）                              │</span></span>
<span class="line"><span>│  • 混合锁定（Hybrid Pinning）                                   │</span></span>
<span class="line"><span>│                                                                    │</span></span>
<span class="line"><span>└───────────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>*/</span></span></code></pre></div><hr><h2 id="_6-超时重试与错误处理" tabindex="-1">6. 超时重试与错误处理 <a class="header-anchor" href="#_6-超时重试与错误处理" aria-label="Permalink to &quot;6. 超时重试与错误处理&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>超时重试与错误处理深度分析：</span></span>
<span class="line"><span>┌───────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  超时处理：                                                     │</span></span>
<span class="line"><span>│  ┌───────────────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │  // 超时处理                                                │</span></span>
<span class="line"><span>│  │  request.timeoutInterval = 30                              │</span></span>
<span class="line"><span>│  │  URLSession.shared.dataTask(with: url) { data, response, error in  │</span></span>
<span class="line"><span>│  │      if let error = error as? URLError {                 │</span></span>
<span class="line"><span>│  │          switch error.code {                             │</span></span>
<span class="line"><span>│  │          case .timedOut:                                   │</span></span>
<span class="line"><span>│  │              // 超时处理                                      │</span></span>
<span class="line"><span>│  │          case .notConnectedToInternet:                      │</span></span>
<span class="line"><span>│  │              // 无网络连接                                    │</span></span>
<span class="line"><span>│  │          case .networkConnectionLost:                      │</span></span>
<span class="line"><span>│  │              // 网络断开                                    │</span></span>
<span class="line"><span>│  │          default:                                         │</span></span>
<span class="line"><span>│  │              // 其他错误                                     │</span></span>
<span class="line"><span>│  │          }                                                 │</span></span>
<span class="line"><span>│  │      }                                                     │</span></span>
<span class="line"><span>│  │  }.resume()                                                │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  重试策略：                                                 │</span></span>
<span class="line"><span>│  │  ┌───────────────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │  │  // 指数退避                                                │</span></span>
<span class="line"><span>│  │  │  func retry(with url: URL, maxRetries: Int = 3) {         │</span></span>
<span class="line"><span>│  │  │      for attempt in 0..&lt;maxRetries {                      │</span></span>
<span class="line"><span>│  │  │          let delay = pow(2, Double(attempt)) * 1.0        │</span></span>
<span class="line"><span>│  │  │          DispatchQueue.global().asyncAfter(deadline: .now() + delay) {  │</span></span>
<span class="line"><span>│  │  │              // 执行请求                                    │</span></span>
<span class="line"><span>│  │  │              URLSession.shared.dataTask(with: url) { data, _, error in  │</span></span>
<span class="line"><span>│  │  │                  if error == nil { return }                │</span></span>
<span class="line"><span>│  │  │              }.resume()                                    │</span></span>
<span class="line"><span>│  │  │          }                                                 │</span></span>
<span class="line"><span>│  │  │      }                                                     │</span></span>
<span class="line"><span>│  │  │  }                                                        │</span></span>
<span class="line"><span>│  │  │                                                            │</span></span>
<span class="line"><span>│  │  │  // 重试策略对比                                            │</span></span>
<span class="line"><span>│  │  │  • 固定间隔：1s, 1s, 1s, 1s                            │</span></span>
<span class="line"><span>│  │  │  • 指数退避：1s, 2s, 4s, 8s, 16s                      │</span></span>
<span class="line"><span>│  │  │  • 随机退避：1-3s, 2-6s, 4-12s, 8-24s                 │</span></span>
<span class="line"><span>│  │  │  • 熔断器：连续失败 N 次后暂停 M 秒                        │</span></span>
<span class="line"><span>│  │  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  重试策略总结：                                               │</span></span>
<span class="line"><span>│  │  • 固定间隔重试：简单但可能加剧网络压力                          │</span></span>
<span class="line"><span>│  │  • 指数退避：推荐方案，逐步增加重试间隔                         │</span></span>
<span class="line"><span>│  │  • 随机退避：避免雪崩效应                                     │</span></span>
<span class="line"><span>│  │  • 熔断器：连续失败后暂停，避免无效重试                        │</span></span>
<span class="line"><span>│  │  • 重试次数限制：最多 3-5 次                                  │</span></span>
<span class="line"><span>│  │  • 超时设置：30s 请求，60s 资源                               │</span></span>
<span class="line"><span>│  │  • URLError 处理：网络状态分类处理                            │</span></span>
<span class="line"><span>│  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│                                                                    │</span></span>
<span class="line"><span>│  超时重试总结：                                                   │</span></span>
<span class="line"><span>│  • 固定间隔：简单但加剧网络压力                                    │</span></span>
<span class="line"><span>│  • 指数退避：推荐方案                                          │</span></span>
<span class="line"><span>│  • 随机退避：避免雪崩效应                                       │</span></span>
<span class="line"><span>│  • 熔断器：连续失败后暂停                                        │</span></span>
<span class="line"><span>│  • 重试次数：3-5 次                                             │</span></span>
<span class="line"><span>│  • 超时：30s 请求，60s 资源                                    │</span></span>
<span class="line"><span>│  • URLError：网络状态分类处理                                     │</span></span>
<span class="line"><span>│                                                                    │</span></span>
<span class="line"><span>└───────────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>*/</span></span></code></pre></div><hr><h2 id="_7-网络状态监测与缓存" tabindex="-1">7. 网络状态监测与缓存 <a class="header-anchor" href="#_7-网络状态监测与缓存" aria-label="Permalink to &quot;7. 网络状态监测与缓存&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>网络状态监测与缓存深度分析：</span></span>
<span class="line"><span>┌───────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  网络状态监测：                                                 │</span></span>
<span class="line"><span>│  ┌───────────────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │  // 网络状态监测                                             │</span></span>
<span class="line"><span>│  │  import Network                                             │</span></span>
<span class="line"><span>│  │  let monitor = NWPathMonitor()                              │</span></span>
<span class="line"><span>│  │  monitor.pathUpdateHandler = { path in                      │</span></span>
<span class="line"><span>│  │      if path.status == .satisfied {                        │</span></span>
<span class="line"><span>│  │          print(&quot;网络可用&quot;)                                  │</span></span>
<span class="line"><span>│  │      } else {                                              │</span></span>
<span class="line"><span>│  │          print(&quot;网络不可用&quot;)                                │</span></span>
<span class="line"><span>│  │      }                                                     │</span></span>
<span class="line"><span>│  │      if path.usesInterfaceType(.wifi) {                    │</span></span>
<span class="line"><span>│  │          print(&quot;Wi-Fi 网络&quot;)                                │</span></span>
<span class="line"><span>│  │      } else if path.usesInterfaceType(.cellular) {         │</span></span>
<span class="line"><span>│  │          print(&quot;蜂窝网络&quot;)                                  │</span></span>
<span class="line"><span>│  │      } else if path.usesInterfaceType(.wiredEthernet) {    │</span></span>
<span class="line"><span>│  │          print(&quot;有线网络&quot;)                                  │</span></span>
<span class="line"><span>│  │      }                                                     │</span></span>
<span class="line"><span>│  │  }                                                          │</span></span>
<span class="line"><span>│  │  monitor.start(queue: .global())                            │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  网络状态类型：                                              │</span></span>
<span class="line"><span>│  │  • .satisfied — 网络可用                                    │</span></span>
<span class="line"><span>│  │  • .unsatisfied — 网络不可用                                │</span></span>
<span class="line"><span>│  │  • .requiresConnection — 需要连接                           │</span></span>
<span class="line"><span>│  │  • .requiresLowLatency — 需要低延迟                        │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  网络类型：                                                │</span></span>
<span class="line"><span>│  │  • .wifi — Wi-Fi 网络                                    │</span></span>
<span class="line"><span>│  │  • .cellular — 蜂窝网络                                    │</span></span>
<span class="line"><span>│  │  • .wiredEthernet — 有线网络                              │</span></span>
<span class="line"><span>│  │  • .loopback — 回环地址                                    │</span></span>
<span class="line"><span>│  │  • .other — 其他网络类型                                   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  缓存策略：                                                 │</span></span>
<span class="line"><span>│  │  ┌───────────────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │  │  // URLCache（网络缓存）                                  │</span></span>
<span class="line"><span>│  │  │  let cache = URLCache(memoryCapacity: 50*1024*1024,      │</span></span>
<span class="line"><span>│  │  │      diskCapacity: 100*1024*1024, diskPath: nil)         │</span></span>
<span class="line"><span>│  │  │                                                            │</span></span>
<span class="line"><span>│  │  │  // 缓存策略                                              │</span></span>
<span class="line"><span>│  │  │  • .useProtocolCachePolicy — 按协议缓存策略              │</span></span>
<span class="line"><span>│  │  │  • .reloadIgnoringLocalCacheData — 忽略缓存              │</span></span>
<span class="line"><span>│  │  │  • .returnCacheDataElseLoad — 先缓存后加载                │</span></span>
<span class="line"><span>│  │  │  • .returnCacheDataDontLoad — 仅从缓存加载               │</span></span>
<span class="line"><span>│  │  │  • .reloadRevalidatingCacheData — 验证缓存               │</span></span>
<span class="line"><span>│  │  │                                                            │</span></span>
<span class="line"><span>│  │  │  // 自定义缓存                                            │</span></span>
<span class="line"><span>│  │  │  class NetworkCache {                                    │</span></span>
<span class="line"><span>│  │  │      private var cache = [URL: Data]()                    │</span></span>
<span class="line"><span>│  │  │      private let maxSize = 100 * 1024 * 1024             │</span></span>
<span class="line"><span>│  │  │      private var currentSize = 0                          │</span></span>
<span class="line"><span>│  │  │                                                            │</span></span>
<span class="line"><span>│  │  │      func get(url: URL) -&gt; Data? {                      │</span></span>
<span class="line"><span>│  │  │          return cache[url]                               │</span></span>
<span class="line"><span>│  │  │      }                                                  │</span></span>
<span class="line"><span>│  │  │                                                            │</span></span>
<span class="line"><span>│  │  │      func set(url: URL, data: Data) {                   │</span></span>
<span class="line"><span>│  │  │          if currentSize + data.count &gt; maxSize {         │</span></span>
<span class="line"><span>│  │  │              // 清理缓存                                    │</span></span>
<span class="line"><span>│  │  │              cache.removeValue(forKey: cache.keys.first!)  │</span></span>
<span class="line"><span>│  │  │          }                                                │</span></span>
<span class="line"><span>│  │  │          cache[url] = data                                │</span></span>
<span class="line"><span>│  │  │          currentSize += data.count                         │</span></span>
<span class="line"><span>│  │  │      }                                                    │</span></span>
<span class="line"><span>│  │  │  }                                                        │</span></span>
<span class="line"><span>│  │  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  网络状态监测与缓存总结：                                     │</span></span>
<span class="line"><span>│  │  • NWPathMonitor（网络状态监测）                              │</span></span>
<span class="line"><span>│  │  • NWPath（网络路径）                                        │</span></span>
<span class="line"><span>│  │  • URLCache（网络缓存）                                      │</span></span>
<span class="line"><span>│  │  • 缓存策略（useProtocolCachePolicy 等）                   │</span></span>
<span class="line"><span>│  │  • 自定义缓存（LRU 替换、大小限制）                         │</span></span>
<span class="line"><span>│  │  • 网络类型检测（WiFi/Cellular/Wired）                     │</span></span>
<span class="line"><span>│  │  • 网络状态分类（satisfied/unsatisfied/requiresConnection）  │</span></span>
<span class="line"><span>│  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│                                                                    │</span></span>
<span class="line"><span>│  网络状态监测与缓存总结：                                         │</span></span>
<span class="line"><span>│  • NWPathMonitor（网络状态监测）                                  │</span></span>
<span class="line"><span>│  • NWPath（网络路径）                                            │</span></span>
<span class="line"><span>│  • URLCache（网络缓存）                                          │</span></span>
<span class="line"><span>│  • 缓存策略（useProtocolCachePolicy 等）                       │</span></span>
<span class="line"><span>│  • 自定义缓存（LRU 替换、大小限制）                            │</span></span>
<span class="line"><span>│  • 网络类型检测（WiFi/Cellular/Wired）                         │</span></span>
<span class="line"><span>│  • 网络状态分类（satisfied/unsatisfied/requiresConnection）       │</span></span>
<span class="line"><span>│                                                                    │</span></span>
<span class="line"><span>└───────────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>*/</span></span></code></pre></div><hr><h2 id="_8-ats-与-ssl-pinning" tabindex="-1">8. ATS 与 SSL Pinning <a class="header-anchor" href="#_8-ats-与-ssl-pinning" aria-label="Permalink to &quot;8. ATS 与 SSL Pinning&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ATS 与 SSL Pinning 深度分析：</span></span>
<span class="line"><span>┌────────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  ATS（App Transport Security）：                                  │</span></span>
<span class="line"><span>│  ┌───────────────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │  // ATS 配置                                                │</span></span>
<span class="line"><span>│  │  Info.plist:                                                │</span></span>
<span class="line"><span>│  │  &lt;key&gt;NSAppTransportSecurity&lt;/key&gt;                         │</span></span>
<span class="line"><span>│  │  &lt;dict&gt;                                                     │</span></span>
<span class="line"><span>│  │      &lt;key&gt;NSAllowsArbitraryLoads&lt;/key&gt;                     │</span></span>
<span class="line"><span>│  │      &lt;true/&gt;                                                │</span></span>
<span class="line"><span>│  │      &lt;key&gt;NSExceptionDomains&lt;/key&gt;                         │</span></span>
<span class="line"><span>│  │      &lt;dict&gt;                                                 │</span></span>
<span class="line"><span>│  │          &lt;key&gt;example.com&lt;/key&gt;                             │</span></span>
<span class="line"><span>│  │          &lt;dict&gt;                                             │</span></span>
<span class="line"><span>│  │              &lt;key&gt;NSExceptionAllowsInsecureHTTPLoads&lt;/key&gt;  │</span></span>
<span class="line"><span>│  │              &lt;true/&gt;                                        │</span></span>
<span class="line"><span>│  │              &lt;key&gt;NSThirdPartyExceptionAllowsInsecureHTTPLoads&lt;/key&gt;  │</span></span>
<span class="line"><span>│  │              &lt;true/&gt;                                        │</span></span>
<span class="line"><span>│  │          &lt;/dict&gt;                                             │</span></span>
<span class="line"><span>│  │      &lt;/dict&gt;                                                 │</span></span>
<span class="line"><span>│  │  &lt;/dict&gt;                                                    │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  ATS 要求：                                                │</span></span>
<span class="line"><span>│  │  • TLS 1.2 或更高版本                                    │</span></span>
<span class="line"><span>│  │  • 证书由受信任的 CA 颁发                                  │</span></span>
<span class="line"><span>│  │  • 密钥交换算法：ECDHE 或 DH（≥ 2048 位）                │</span></span>
<span class="line"><span>│  │  • 签名算法：SHA-256 或更高                                │</span></span>
<span class="line"><span>│  │  • 禁止 HTTP 协议（必须 HTTPS）                           │</span></span>
<span class="line"><span>│  │  • 禁止弱加密套件                                          │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  ATS 例外配置：                                             │</span></span>
<span class="line"><span>│  │  • NSAllowsArbitraryLoads — 允许所有 HTTP 连接              │</span></span>
<span class="line"><span>│  │  • NSExceptionDomains — 特定域名例外                      │</span></span>
<span class="line"><span>│  │  • NSThirdPartyExceptionAllowsInsecureHTTPLoads — 第三方例外  │</span></span>
<span class="line"><span>│  │  • NSIncludesSubdomains — 包含子域名                      │</span></span>
<span class="line"><span>│  │  • NSEncryptionRequired — 必须加密                        │</span></span>
<span class="line"><span>│  │  • NSPinnningExceptionDomains — SSL Pinning 例外          │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  ATS 安全性：                                              │</span></span>
<span class="line"><span>│  │  • 默认开启 ATS（iOS 9+）                                 │</span></span>
<span class="line"><span>│  │  • 禁止 HTTP 明文传输                                      │</span></span>
<span class="line"><span>│  │  • 强制 TLS 1.2+                                           │</span></span>
<span class="line"><span>│  │  • 证书必须受信任                                           │</span></span>
<span class="line"><span>│  │  • 禁止弱加密套件                                          │</span></span>
<span class="line"><span>│  │  • 建议：不关闭 ATS，配置例外域名                          │</span></span>
<span class="line"><span>│  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  SSL Pinning：                                              │</span></span>
<span class="line"><span>│  │  ┌───────────────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │  │  // SSL Pinning 实现                                        │</span></span>
<span class="line"><span>│  │  │  func urlSession(_ session: URLSession,                   │</span></span>
<span class="line"><span>│  │  │      didReceive challenge: URLAuthenticationChallenge,    │</span></span>
<span class="line"><span>│  │  │      completionHandler: @escaping (URLSession.             │</span></span>
<span class="line"><span>│  │  │      AuthChallengeDisposition, URLCredential?) -&gt; Void) {  │</span></span>
<span class="line"><span>│  │  │      if challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust {  │</span></span>
<span class="line"><span>│  │  │          let serverTrust = challenge.protectionSpace.serverTrust!  │</span></span>
<span class="line"><span>│  │  │          let credential = URLCredential(trust: serverTrust)  │</span></span>
<span class="line"><span>│  │  │          completionHandler(.useCredential, credential)     │</span></span>
<span class="line"><span>│  │  │      } else {                                            │</span></span>
<span class="line"><span>│  │  │          completionHandler(.cancelAuthenticationChallenge, nil)  │</span></span>
<span class="line"><span>│  │  │      }                                                      │</span></span>
<span class="line"><span>│  │  │  }                                                        │</span></span>
<span class="line"><span>│  │  │                                                            │</span></span>
<span class="line"><span>│  │  │  // 证书验证                                             │</span></span>
<span class="line"><span>│  │  │  SecTrustEvaluate(serverTrust, &amp;trustResult)              │</span></span>
<span class="line"><span>│  │  │  SecTrustGetCertificateCount(serverTrust)                 │</span></span>
<span class="line"><span>│  │  │  SecTrustGetCertificateAtIndex(serverTrust, 0)            │</span></span>
<span class="line"><span>│  │  │                                                            │</span></span>
<span class="line"><span>│  │  │  // SSL Pinning 方案                                        │</span></span>
<span class="line"><span>│  │  │  • 公钥锁定（PublicKey Pinning）                          │</span></span>
<span class="line"><span>│  │  │  • 证书锁定（Certificate Pinning）                      │</span></span>
<span class="line"><span>│  │  │  • 指纹锁定（Fingerprint Pinning）                      │</span></span>
<span class="line"><span>│  │  │  • 混合锁定（Hybrid Pinning）                          │</span></span>
<span class="line"><span>│  │  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  │  ATS 与 SSL Pinning 总结：                                  │</span></span>
<span class="line"><span>│  │  • ATS 默认开启（iOS 9+），强制 HTTPS                      │</span></span>
<span class="line"><span>│  │  • ATS 配置例外域名（不关闭 ATS）                              │</span></span>
<span class="line"><span>│  │  • SSL Pinning 防止中间人攻击                              │</span></span>
<span class="line"><span>│  │  • 公钥锁定（PublicKey Pinning）                              │</span></span>
<span class="line"><span>│  │  • 证书锁定（Certificate Pinning）                          │</span></span>
<span class="line"><span>│  │  • 指纹锁定（Fingerprint Pinning）                          │</span></span>
<span class="line"><span>│  │  • 混合锁定（Hybrid Pinning）                               │</span></span>
<span class="line"><span>│  │  • 证书验证（SecTrustEvaluate）                              │</span></span>
<span class="line"><span>│  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│  │                                                               │   │</span></span>
<span class="line"><span>│  └───────────────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│                                                                    │</span></span>
<span class="line"><span>│  ATS 与 SSL Pinning 总结：                                        │</span></span>
<span class="line"><span>│  • ATS 默认开启（iOS 9+），强制 HTTPS                           │</span></span>
<span class="line"><span>│  • ATS 配置例外域名（不关闭 ATS）                                  │</span></span>
<span class="line"><span>│  • SSL Pinning 防止中间人攻击                                    │</span></span>
<span class="line"><span>│  • 公钥锁定（PublicKey Pinning）                                  │</span></span>
<span class="line"><span>│  • 证书锁定（Certificate Pinning）                              │</span></span>
<span class="line"><span>│  • 指纹锁定（Fingerprint Pinning）                              │</span></span>
<span class="line"><span>│  • 混合锁定（Hybrid Pinning）                                   │</span></span>
<span class="line"><span>│  • 证书验证（SecTrustEvaluate）                                  │</span></span>
<span class="line"><span>│                                                                    │</span></span>
<span class="line"><span>└───────────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>*/</span></span></code></pre></div><hr><h2 id="_9-面试考点汇总" tabindex="-1">9. 面试考点汇总 <a class="header-anchor" href="#_9-面试考点汇总" aria-label="Permalink to &quot;9. 面试考点汇总&quot;">​</a></h2><h3 id="高频面试题" tabindex="-1">高频面试题 <a class="header-anchor" href="#高频面试题" aria-label="Permalink to &quot;高频面试题&quot;">​</a></h3><p><strong>Q1: HTTP/HTTPS 的区别？</strong></p><p><strong>答</strong>：</p><ul><li>HTTP：明文传输，无加密</li><li>HTTPS：TLS 加密，证书验证，安全传输</li><li>HTTPS 握手：Client Hello → Server Hello → Certificate → 握手完成</li></ul><p><strong>Q2: URLSession 的使用？</strong></p><p><strong>答</strong>：</p><ul><li>dataTask：数据下载</li><li>downloadTask：文件下载</li><li>uploadTask：数据/文件上传</li><li>background session：后台传输</li><li>配置：timeout、cache、headers、connection limit</li></ul><p><strong>Q3: SSL Pinning 原理？</strong></p><p><strong>答</strong>：</p><ul><li>防止中间人攻击</li><li>公钥锁定/证书锁定/指纹锁定</li><li>SecTrustEvaluate 证书验证</li><li>URLCredential(trust:) 创建凭据</li></ul><p><strong>Q4: ATS 是什么？</strong></p><p><strong>答</strong>：</p><ul><li>App Transport Security（iOS 9+ 默认开启）</li><li>强制 HTTPS 连接</li><li>例外域名配置（不关闭 ATS）</li><li>TLS 1.2+ 要求</li></ul><p><strong>Q5: 网络超时重试策略？</strong></p><p><strong>答</strong>：</p><ul><li>指数退避：1s, 2s, 4s, 8s</li><li>固定间隔：1s, 1s, 1s</li><li>随机退避：1-3s, 2-6s</li><li>熔断器：连续失败 N 次后暂停</li></ul><p><strong>Q6: 网络缓存策略？</strong></p><p><strong>答</strong>：</p><ul><li>URLCache：内存+磁盘缓存</li><li>缓存策略：useProtocolCachePolicy、reloadIgnoringLocalCacheData</li><li>自定义缓存：LRU 替换、大小限制</li></ul><p><strong>Q7: NWPathMonitor 用途？</strong></p><p><strong>答</strong>：</p><ul><li>网络状态监测</li><li>网络类型检测（WiFi/Cellular/Wired）</li><li>网络路径监控（satisfied/unsatisfied）</li></ul><hr><h2 id="_10-参考资源" tabindex="-1">10. 参考资源 <a class="header-anchor" href="#_10-参考资源" aria-label="Permalink to &quot;10. 参考资源&quot;">​</a></h2><ul><li><a href="https://developer.apple.com/documentation/foundation/urlsession" target="_blank" rel="noreferrer">Apple: URLSession Reference</a></li><li><a href="https://developer.apple.com/documentation/foundation/url_loading_system" target="_blank" rel="noreferrer">Apple: URL Loading System</a></li><li><a href="https://developer.apple.com/documentation/network" target="_blank" rel="noreferrer">Apple: Network Framework</a></li><li><a href="https://developer.apple.com/documentation/bundleresources/entitlements/com_apple_security_entitlements/app_transport_security" target="_blank" rel="noreferrer">Apple: ATS</a></li><li><a href="https://developer.apple.com/documentation/security/certificate_key_and_trust_services" target="_blank" rel="noreferrer">Apple: SSL/TLS</a></li><li><a href="https://developer.apple.com/documentation/authencation" target="_blank" rel="noreferrer">Apple: OAuth2</a></li><li><a href="https://httpwg.org/specs/rfc7540.html" target="_blank" rel="noreferrer">Apple: HTTP/2</a></li><li><a href="https://httpwg.org/specs/rfc9114.html" target="_blank" rel="noreferrer">Apple: HTTP/3</a></li><li><a href="https://nshipster.com/urlsession" target="_blank" rel="noreferrer">NSHipster: URLSession</a></li><li><a href="https://nshipster.com/nwpathmonitor" target="_blank" rel="noreferrer">NSHipster: NWPathMonitor</a></li><li><a href="https://developer.apple.com/videos/play/wwdc2020/10203/" target="_blank" rel="noreferrer">WWDC 2020: Network Framework</a></li><li><a href="https://developer.apple.com/videos/play/wwdc2021/10227/" target="_blank" rel="noreferrer">WWDC 2021: Advanced Networking</a></li><li><a href="https://developer.apple.com/videos/play/wwdc2022/10030/" target="_blank" rel="noreferrer">WWDC 2022: Networking with URLSession</a></li><li><a href="https://developer.apple.com/videos/play/wwdc2023/10124/" target="_blank" rel="noreferrer">WWDC 2023: Networking in iOS</a></li></ul>`,54)])])}const T=s(e,[["render",i]]);export{h as __pageData,T as default};
